// Solution
function solve(s) {
    let stack = [];
    let nested = false;
    for (let i = 0; i < s.length; i++) {
        if (s[i] === '<') {
            if (s[i + 1] === '/') {
                stack.pop();
            } else {
                stack.push(s[i + 1]);
                if (stack.length > 1 && !['img', 'input', 'br'].includes(stack[stack.length - 2])) {
                    nested = true;
                }
            }
        }
    }
    return !nested;
}

