class Solution:
    def solve(self, s: str) -> bool:
        stack = []
        nested = False
        for i in range(len(s)):
            if s[i] === '<':
                if s[i + 1] === '/':
                    stack.pop()
                else:
                    stack.append(s[i + 1])
                    if len(stack) > 1 and stack[-2] not in ['img', 'input', 'br']:
                        nested = True
        return not nested
